using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // BREAKING CHANGE 1 — Discriminator property renamed "$type" in EF Core 9.
            // Existing 500K documents use "Discriminator"; direct SQL queries reference
            // c.Discriminator.  Preserve the old property name.
            b.HasDiscriminator<string>("Discriminator");

            // BREAKING CHANGE 2 — id synthesis changed.
            // EF Core 8 wrote id as "Product|{key}".  EF Core 9 maps the PK directly
            // to the JSON "id" property.  We keep the legacy composite format so
            // existing documents stay readable without a data migration.
            b.Property<string>("__id")
                .ToJsonProperty("id")
                .HasValueGenerator<LegacyCosmosIdGenerator>();

            // BREAKING CHANGE 3 — HasIndex now throws for the Cosmos provider.
            // It was silently ignored in EF Core 8.  Removed.
            // (was: b.HasIndex(p => p.Sku);)
        });
    }
}

class Product
{
    public int Id { get; set; }
    public string Sku { get; set; } = null!;
}

/// <summary>
/// Reproduces the EF Core 8 Cosmos id format ("Product|{key}") so that
/// new documents remain compatible with the 500K existing ones.
/// </summary>
class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override string Next(EntityEntry entry)
        => $"Product|{entry.Property("Id").CurrentValue}";

    public override bool GeneratesTemporaryValues => false;
}

