using Microsoft.EntityFrameworkCore;

class CosmosQuery
{
    async Task FindProductsAsync(ProductContext ctx)
    {
        // Direct Cosmos SQL — still works because we preserved "Discriminator"
        // as the JSON property name (see ProductContext).
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // BREAKING CHANGE 4 — Synchronous LINQ (ToList, First, …) removed in
        // EF Core 9 Cosmos provider.  Must use async counterparts.
        var products = await ctx.Products
            .Where(p => p.Sku == "ABC")
            .ToListAsync();
    }
}

